/**
 * Compute the next `requiredIf` array when appending a new condition.
 *
 * Conditions are accumulated (chainable) and combined with OR semantics: the
 * attribute is required as soon as any of the recorded conditions matches.
 */
export const appendRequiredIf = (
  props: SchemaProps,
  attributeName: string,
  values: unknown[]
): RequiredIfCondition[] => [...(props.requiredIf ?? []), { attributeName, values }]

/**
 * Evaluate whether an attribute's `requiredIf` conditions are triggered given
 * the values of its sibling attributes.
 *
 * A condition matches when its controlling sibling is present (not `undefined`)
 * and, if trigger values are provided, its value is one of them. An absent
 * controlling attribute skips evaluation of its condition.
 */
export const isRequiredIfTriggered = (
  requiredIf: RequiredIfCondition[] | undefined,
  siblings: Record<string, unknown>
): boolean => {
  if (requiredIf === undefined) {
    return false
  }

  return requiredIf.some(({ attributeName, values }) => {
    const controllingValue = siblings[attributeName]

    if (controllingValue === undefined) {
      return false
    }

    return values.length === 0 || values.includes(controllingValue)
  })
}
